/// <summary>
/// This class is an controller class for CapexId
/// </summary>
internal final class ETGCapexIdController extends SysOperationServiceController
{
}

Method.Source:
protected void new()
{
    super(classStr(ETGCapexIdService), methodStr(ETGCapexIdService, process), SysOperationExecutionMode::Synchronous);
}

/// <summary>
/// This method will return the Caption of the batch job.
/// </summary>
/// <returns>classDescription</returns>
public classDescription defaultCaption()
{
    return "@ETG_New:CapexIDUpdate";
}

/// <summary>
/// This method will return the controller.
/// </summary>
/// <param name = "_executionMode">ExecutionMode.</param>
/// <returns>ETGTrackingCustPaymController</returns>
public static ETGCapexIdController construct(SysOperationExecutionMode _executionMode = SysOperationExecutionMode::Synchronous)
{
    ETGCapexIdController controller;
    controller = new ETGCapexIdController();
    controller.parmExecutionMode(_executionMode);
    return controller;
}

/// <summary>
/// Class entry point. The system will call this method when a designated menu
/// is selected or when execution starts and this class is set as the startup class.
/// </summary>
/// <param name = "_args">The specified arguments.</param>
public static void main(Args _args)
{
    ETGCapexIdController controller;
    controller = ETGCapexIdController::construct();
    controller.parmArgs(_args);
    controller.startOperation();
}
